import hashlib
import time

class Block:
 def __init__(self, index, previous_hash, timestamp, data):
 self.index = index
 self.previous_hash = previous_hash
 self.timestamp = timestamp
 self.data = data
 self.hash = self.calculate_hash()

 def calculate_hash(self):
 data_string = str(self.index) + self.previous_hash + str(self.timestamp) + str(self.data)
 return hashlib.sha256(data_string.encode()).hexdigest()

class Blockchain:
 def __init__(self):
 self.chain = [self.create_genesis_block()]

 def create_genesis_block(self):
 return Block(0, '0', int(time.time()), 'Genesis Block')

 def get_latest_block(self):
 return self.chain[-1]

 def add_block(self, new_block):
 new_block.previous_hash = self.get_latest_block().hash
 new_block.hash = new_block.calculate_hash()
 self.chain.append(new_block)

# Create a new blockchain and add some blocks
my_blockchain = Blockchain()
my_blockchain.add_block(Block(1, my_blockchain.get_latest_block().hash, int(time.time()), 'Transaction 1'))
my_blockchain.add_block(Block(2, my_blockchain.get_latest_block().hash, int(time.time()), 'Transaction 2'))

#include <stdio.h>
#include <string.h>
#include <time.h>
#include <sha2.h>

#define BLOCK_SIZE 1024

typedef struct Block {
 int index;
 char previous_hash[SHA256_DIGEST_LENGTH * 2 + 1];
 time_t timestamp;
 char data[BLOCK_SIZE];
 char hash[SHA256_DIGEST_LENGTH * 2 + 1];
} Block;

typedef struct Blockchain {
 Block *chain;
 int length;
} Blockchain;

void calculate_hash(Block *block) {
 char data_string[BLOCK_SIZE + SHA256_DIGEST_LENGTH * 2 + 1];
 sprintf(data_string, "%d%s%ld%s", block->index, block->previous_hash, block->timestamp, block->data);
 SHA256_CTX sha256;
 SHA256_Init(&sha256);
 SHA256_Update(&sha256, data_string, strlen(data_string));
 SHA256_Final(block->hash, &sha256);
}

Blockchain *create_blockchain() {
 Blockchain *blockchain = malloc(sizeof(Blockchain));
 blockchain->chain = malloc(sizeof(Block));
 blockchain->length = 1;
 return blockchain;
}

void add_block(Blockchain *blockchain, Block *new_block) {
 new_block->previous_hash = blockchain->chain[blockchain->length - 1].hash;
 calculate_hash(new_block);
 blockchain->chain = realloc(blockchain->chain, (blockchain->length + 1) * sizeof(Block));
 blockchain->chain[blockchain->length] = *new_block;
 blockchain->length++;
}

int main() {
 Blockchain *my_blockchain = create_blockchain();
 Block genesis_block;
 genesis_block.index = 0;
 strcpy(genesis_block.previous_hash, "0");
 genesis_block.timestamp = time(NULL);
 strcpy(genesis_block.data, "Genesis Block");
 calculate_hash(&genesis_block);
 my_blockchain->chain[0] = genesis_block;

 Block new_block;
 new_block.index = 1;
 new_block.timestamp = time(NULL);
 strcpy(new_block.data, "Transaction 1");
 add_block(my_blockchain, &new_block);

 return 0;
}
